description:
### What happens?

I encountered an issue where a query executes successfully and returns correct results, but EXPLAIN fails with an Invalid Input Error.
Also,the long execution time is not expected.Given the very small input size, the query should complete in milliseconds.


### To Reproduce

```sql
PRAGMA enable_verification;
CREATE TABLE v0 ( v1 DOUBLE , v2 INT ) ;
INSERT INTO v0 VALUES ( 4 , 1 ) ,( 0 , 2 ) ,( 0 , 9 ) ,( 6 , 2 ) ;
SELECT nullif ( v2 , v2 ) AS result FROM v0 ;
SELECT v1 , v1 FROM v0 WHERE v1 = bitstring ( '1011' , 2147483647 ) ;
SELECT nullif ( 1 , 2 ) AS result ;
SELECT nullif ( NULL , 2 ) AS result ;
SELECT mode ( v1 ) AS mode_value FROM v0 JOIN v0 ON EXTRACT ( HOUR FROM v2 ) = EXTRACT ( HOUR FROM v2 ) ;
SELECT nullif ( NULL , NULL ) AS result ;
SELECT v1 , v2 , nullif ( v2 , v1 ) AS nullified FROM v0 WHERE v2 < 3 ;
SELECT ( SELECT nullif ( v2 , v2 ) FROM v0 ) AS subquery_result ;
CREATE TABLE v3 ( v5 INT , v4 INT ) ;
INSERT INTO v0 VALUES ( 3 , 7 ) ,( 8 , 1000 ) ,( 2 , 3 ) ;
SELECT v0 . v1 , v0 . v2 , nullif ( v0 . v1 , v0 . v1 ) AS null_a_d FROM v0 JOIN v0 ON v0 . v2 = v0 . v2 ;
SELECT nullif ( ( SELECT AVG ( v5 ) FROM v3 ) , 25 ) AS avg_check ;
SELECT nullif ( MAX ( v1 ) , MIN ( v2 ) ) AS max_min_nullified FROM v0 ;
WITH CTE AS ( SELECT v2 , v1 FROM v0 ) SELECT nullif ( v5 , v5 ) FROM v3 ;
SELECT nullif ( COALESCE ( v5 , 2 ) , COALESCE ( v4 , 12 ) ) AS coalesce_result FROM v3 ;
```
## Error Message
Invalid Input Error:
Query succeeded but EXPLAIN failed with: (%s %s %s)

